Material.Shader:

/* This is a vertex program for ...
 */

varying vec3 normal;

void main()
{
  /* Transform the normal. */
  normal = normalize(gl_NormalMatrix*gl_Normal);

  gl_Position = ftransform();
}



/* This is a fragment program ...
 */
uniform int NumLights;
varying vec3 normal;

void main()
{
	gl_FragColor = vec4(normal, 1.0);
}
